(ns string-test
  (:require [ys.v0 :refer :all])
  (:refer-clojure :exclude [atom die print read replace reverse set]))

(defn -main [& args]
  (let [op (first args)]
    (case op
      "len"          (println (.length "hello"))
      "len-utf8"     (println (.length "naïve"))
      "empty?"       (println (.isEmpty ""))
      "blank?"       (println (.isBlank "  \t  "))
      "upper"        (println (.toUpperCase "hello"))
      "lower"        (println (.toLowerCase "HELLO"))
      "trim"         (println (str "[" (.trim "  hi  ") "]"))
      "strip"        (println (str "[" (.strip "   hi   ") "]"))
      "substr"       (println (.substring "hello world" 6))
      "substr-range" (println (.substring "hello world" 0 5))
      "starts"       (println (.startsWith "hello world" "hello"))
      "ends"         (println (.endsWith "hello world" "world"))
      "contains"     (println (.contains "hello world" "lo wo"))
      "indexof"      (println (.indexOf "hello world" "world"))
      "lastindexof"  (println (.lastIndexOf "ababab" "ab"))
      "equals"       (println (.equals "abc" "abc"))
      "equals-ic"    (println (.equalsIgnoreCase "ABC" "abc"))
      "compareto"    (println (.compareTo "abc" "abd"))
      "concat"       (println (.concat "foo" "bar"))
      "repeat"       (println (.repeat "ab" 3))
      "replace"      (println (.replace "foobar" "oo" "OO"))
      "replaceall"   (println (.replaceAll "a1b2c3" "[0-9]" "X"))
      "replacefirst" (println (.replaceFirst "a1b2c3" "[0-9]" "X"))
      "matches"      (println (.matches "abc123" "[a-z]+[0-9]+"))
      "split"        (println (vec (.split "a,b,c,,e" ",")))
      "split-limit"  (println (vec (.split "a,b,c,d" "," 2)))
      "hash"         (println (.hashCode "hello"))
      "format"       (println (String/format "%s=%d" "x" 42))
      "format-pct"   (println (String/format "%.2f%%" 3.14159))
      "join"         (println (String/join "-" ["a" "b" "c"]))
      "join-empty"   (println (str "[" (String/join "," []) "]"))
      "valueof-nil"  (println (String/valueOf nil))
      "valueof-bool" (println (String/valueOf true))
      "valueof-int"  (println (String/valueOf 42))
      "ctor"         (println (String. "hello"))
      "fq-format"    (println (java.lang.String/format "x=%d" 7))
      "chain"        (println (-> "  Hello World  " .trim .toUpperCase))
      (println "usage: string <op>"))))
